#include <stdio.h>
#include <math.h>
#define MOD 1000000007
long long catalan(int n) {
    long long res = 1;
    for (int i = 1; i <= n; i++) {
        res = (res * (4 * i - 2)) / (i + 1);
    }
    return res;
}
long long binomial(int n, int k) {
    long long res = 1;
    for (int i = 1; i <= k; i++) {
        res = (res * (n - i + 1)) / i;
    }
    return res;
}
int main() {
    int T;
    scanf("%d", &T);
    while (T--) {
        int N, K;
        scanf("%d %d", &N, &K);
        long long total = catalan(N / 2);
        long long good = binomial(N / 2, N / 2);
        long long prob = (good * total - 1) % MOD;
        printf("%lld\n", prob);
    }
    return 0;
}

