import java.util.Scanner;
public class Main {
    static final int MOD = 1000000007;
    public static long catalan(int n) {
        long res = 1;
        for (int i = 1; i <= n; i++) {
            res = (res * (4 * i - 2)) / (i + 1);
        }
        return res;
    }
    public static long binomial(int n, int k) {
        long res = 1;
        for (int i = 1; i <= k; i++) {
            res = (res * (n - i + 1)) / i;
        }
        return res;
    }
    public static void main(String[] args) {
        Scanner sc = new Scanner(System.in);
        int T = sc.nextInt();
        while (T-- > 0) {
            int N = sc.nextInt();
            int K = sc.nextInt();
            long total = catalan(N / 2);
            long good = binomial(N / 2, N / 2);
            long prob = (good * total - 1) % MOD;
